239	  void reset()
240	  {
241	    static constexpr int core_num = CPU::NDS_NHART;
242	    static constexpr int reset_val = (1 << core_num) - 1;
243	
244	    platform.resetn.write(0);
245	    auto saved = context_config;
246	    context_config = {};
247	    this->run(1);
248	    context_config = saved;
249	
250	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
251	      spdlog::info("hart {} reset vector: {:#x}", i,
252	                   (uint64_t) platform.reset_vector[i].read());
253	
254	    platform.resetn.write(reset_val);
255	
256	    if (context_config.continue_from)
257	      restore_context(context_config.dir);
258	  }
