102	extern "C" auto sc_main(const int argc, char* argv[]) -> int
103	try {
104	  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
105	  spdlog::set_pattern("[%^%l%$] %v");
106	
107	  const auto args = [&] {
108	    struct args
109	    {
110	      std::string pc_trace_file{};
111	      std::string elf_file{};
112	      std::optional<uint16_t> jtag_port = std::nullopt;
113	      bool memmap = false;
114	      std::string waveform_file{};
115	      unsigned mem_latency = 1;
116	      std::string ilm_file{};
117	      std::string dlm_file{};
118	      std::string kanata_file{};
119	      std::string objdump_file{};
120	      std::string clarity_file{};
121	      std::optional<uint64_t> kanata_loop_start{};
122	      std::optional<uint64_t> kanata_loop_end{};
123	      uint64_t kanata_loop_skip = 0;
124	      uint64_t kanata_loop_record = 1;
125	      std::vector<std::string> reset_vectors{};
126	      bool continue_ctx = false;
127	      bool save_ctx = false;
128	      std::string context_dir = "./saved_ctx/";
129	    } args;
130	
131	    const auto help_and_exit = [] {
132	      print_help();
133	      exit(0);
134	    };
135	
136	    auto p = parser{};
137	    p.shortflag('h', help_and_exit);
138	    p.longflag("help", help_and_exit);
139	    p.longflag("version", [] {
140	      print_version();
141	      exit(0);
142	    });
143	    p.longflag("print-memmap", [&] { args.memmap = true; });
144	    p.longflag("print-config", [] {
145	      print_cpu_configuration();
146	      exit(0);
147	    });
148	    p.longopt("jtag-port", [&](const std::string_view s) {
149	      if (auto n = to_int<uint16_t>(s); n)
150	        args.jtag_port = *n;
151	      else
152	        throw std::runtime_error("invalid number for --jtag-port: "
153	                                 + std::string{s});
154	    });
155	    p.longopt("mem-latency", [&](const std::string_view s) {
156	      if (auto n = to_int<unsigned>(s); n)
157	        args.mem_latency = *n;
158	      else
159	        throw std::runtime_error("invalid number for --mem-latency: "
160	                                 + std::string{s});
161	    });
162	    p.longopt("log-level", [](const std::string_view s) {
163	      if (auto n = to_int<uint16_t>(s); n) {
164	        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
165	        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
166	      } else {
167	        throw std::runtime_error("invalid number for --log-level: "
168	                                 + std::string{s});
169	      }
