29	template<typename CPU>
30	class TraceController
31	{
32	public:
33	  void enable_waveform(CPU& cpu, const std::string& waveform_filename)
34	  {
35	    (void) cpu;
36	    waveform_filename_ = waveform_filename;
37	
38	#ifdef VSIMDEBUG
39	    if (waveform_file_) {
40	      spdlog::info("Tracing is already enabled.");
41	      return;
42	    }
43	    if constexpr (requires { cpu.trace(waveform_file_.get(), 0); }) {
44	      waveform_file_ = std::make_unique<VERILATORTRACER>();
45	      cpu.contextp()->traceEverOn(true);
46	      cpu.trace(waveform_file_.get(), 0);
47	      waveform_file_->open(waveform_filename_.c_str());
48	      spdlog::info("Writing traces to {}", waveform_filename_);
49	      return;
50	    }
51	#endif
52	
53	    spdlog::critical("Waveform is not supported.");
54	    std::exit(EXIT_FAILURE);
55	  }
56	
57	  void enable_pc_trace(const std::string& filename)
58	  {
59	    if (pc_trace_enabled_) {
60	      spdlog::warn("PC tracing is already enabled.");
61	      return;
62	    }
63	
64	    pc_trace_file_.open(filename);
65	    if (!pc_trace_file_.is_open()) {
66	      spdlog::critical("Failed to open PC trace file: {}", filename);
67	      std::exit(EXIT_FAILURE);
68	    }
69	
70	    pc_trace_file_ << "cycle,core,pc\n";
71	    pc_trace_enabled_ = true;
72	    cycle_count_ = 0;
73	    spdlog::info("Writing PC trace to {}", filename);
74	  }
75	
76	  void enable_kanata(CPU& cpu,
77	                     const std::string& filename,
78	                     const std::string& objdump_file = "",
79	                     std::optional<kanata::LoopGate> gate = std::nullopt)
80	  {
81	    if (pipeline_viewer_) {
82	      spdlog::warn("Pipeline viewer is already enabled.");
83	      return;
84	    }
85	
86	    pipeline_viewer_ =
87	      pipeview::make_kanata_viewer(cpu, filename, objdump_file, gate);
88	    if (!pipeline_viewer_)
89	      spdlog::warn("Kanata pipeline viewer not available for this CPU.");
90	  }
91	
92	  void enable_clarity(CPU& cpu, const std::string& filename,
93	                      const std::string& objdump_file = "",
94	                      std::optional<kanata::LoopGate> gate = std::nullopt)
95	  {
96	    if (pipeline_viewer_) {
97	      spdlog::warn("Pipeline viewer is already enabled.");
98	      return;
99	    }
100	
101	    pipeline_viewer_ =
102	      pipeview::make_clarity_viewer(cpu, filename, objdump_file, gate);
103	    if (!pipeline_viewer_)
104	      spdlog::warn("Clarity pipeline viewer not available for this CPU.");
105	  }
106	
107	  void on_cycle(CPU& cpu)
108	  {
109	    if (pipeline_viewer_)
110	      pipeline_viewer_->on_cycle();
111	    if (pc_trace_enabled_)
112	      dump_cycle_pcs(cpu);
113	    ++cycle_count_;
114	  }
115	
116	  bool pipeview_wants_exit() const
117	  {
118	    return pipeline_viewer_ && pipeline_viewer_->wants_exit();
119	  }
120	
121	  void dump_cycle_pcs(CPU& cpu)
122	  {
123	    if constexpr (requires { cpu.get_committed_pc(); }) {
124	      auto committed_pcs = cpu.get_committed_pc();
125	      for (size_t core = 0; core < committed_pcs.size(); ++core) {
126	        for (auto pc: committed_pcs[core]) {
127	          pc_trace_file_ << cycle_count_ << "," << core << "," << std::hex
128	                         << "0x" << pc << std::dec << "\n";
129	        }
130	      }
131	    }
132	  }
133	
134	  void close()
135	  {
136	#ifdef VSIMDEBUG
137	    if (waveform_file_)
138	      waveform_file_->close();
139	#endif
140	    disable_pc_trace();
141	    disable_pipeview();
142	  }
143	
144	  void disable_pc_trace()
145	  {
146	    if (pc_trace_enabled_) {
147	      pc_trace_file_.close();
148	      pc_trace_enabled_ = false;
149	      spdlog::info("PC trace closed");
150	    }
151	  }
152	
153	  void disable_pipeview()
154	  {
155	    if (pipeline_viewer_) {
156	      pipeline_viewer_->close();
157	      pipeline_viewer_.reset();
158	      spdlog::info("Pipeline viewer closed");
159	    }
160	  }
161	
162	  auto get_cycles(const sc_core::sc_clock& clk) const -> std::uint64_t
163	  {
164	    const auto time_resolution = sc_core::sc_get_time_resolution();
165	    const auto divider = clk.period().value() / time_resolution.value();
166	    return sc_core::sc_time_stamp().value() / divider;
167	  }
168	
169	  void log_committed_pcs(CPU& cpu)
170	  {
171	    if constexpr (requires { cpu.get_last_committed_pc(); }) {
172	      auto pcs = cpu.get_last_committed_pc();
173	      for (size_t core = 0; core < pcs.size(); ++core) {
174	        std::string pc_list;
175	        for (const auto& pc: pcs[core])
176	          pc_list += fmt::format("0x{:x} ", pc);
177	        spdlog::info("Core {} last PCs: {}", core, pc_list);
178	      }
179	    }
180	  }
181	
182	private:
183	  std::unique_ptr<pipeview::PipelineViewer<CPU>> pipeline_viewer_;
184	  std::ofstream pc_trace_file_;
185	  bool pc_trace_enabled_ = false;
186	  std::uint64_t cycle_count_ = 0;
187	  std::string waveform_filename_;
188	
189	#ifdef VSIMDEBUG
190	  std::unique_ptr<VERILATORTRACER> waveform_file_{};
191	#endif
192	};
