29	/// Models a single in-order pipeline slot.
30	/// Port of Python InorderPipe from tools/andes45.py.
31	class InorderPipe
32	{
33	public:
34	  struct UpdateResult
35	  {
36	    std::vector<std::optional<PcId>> stage_start;
37	    std::vector<std::optional<PcId>> stage_end;
38	    std::optional<PcId> retire;
39	  };
40	
41	  InorderPipe(int stage_num, SequentialIndexMap& id_map)
42	      : id_map_(id_map),
43	        stage_status_(stage_num, std::nullopt),
44	        stage_num_(stage_num)
45	  {}
46	
47	  /// Update pipeline state with new per-stage PCs.
48	  /// stages_pc[i] = nullopt means no instruction at stage i.
49	  UpdateResult update(const std::vector<std::optional<uint64_t>>& stages_pc)
50	  {
51	    UpdateResult res;
52	    res.stage_start.resize(stage_num_, std::nullopt);
53	    res.stage_end.resize(stage_num_, std::nullopt);
54	    std::vector<std::optional<PcId>> new_status(stage_num_, std::nullopt);
55	
56	    // Process stages 0..N-2
57	    for (int i = 0; i < stage_num_ - 1; ++i) {
58	      auto& pcid = stage_status_[i];
59	      if (!pcid)
60	        continue;
61	
62	      if (stages_pc[i] && pcid->pc == *stages_pc[i]) {
63	        // stall
64	        new_status[i] = pcid;
65	      } else if (stages_pc[i + 1] && pcid->pc == *stages_pc[i + 1]) {
66	        // forward to next stage
67	        new_status[i + 1] = pcid;
68	        res.stage_start[i + 1] = pcid;
69	      } else {
70	        // killed
71	        res.stage_end[i] = pcid;
72	      }
73	    }
74	
75	    // Look up ID for first stage
76	    auto& new_pc = stages_pc[0];
77	    if (new_pc) {
78	      if (!stage_status_[0] || *new_pc != stage_status_[0]->pc) {
79	        id_map_.update(*new_pc);
80	        auto new_id = id_map_.pop(*new_pc);
81	        new_status[0] = PcId{*new_pc, new_id};
82	        res.stage_start[0] = new_status[0];
83	      }
84	    }
85	
86	    // Retire last stage
87	    if (stage_status_.back()) {
88	      if (!new_status.back()
89	          || new_status.back()->id != stage_status_.back()->id)
90	      {
91	        res.retire = stage_status_.back();
92	      }
93	    }
94	
95	    stage_status_ = std::move(new_status);
96	    return res;
97	  }
98	
99	private:
100	  SequentialIndexMap& id_map_;
101	  std::vector<std::optional<PcId>> stage_status_;
102	  int stage_num_;
103	};
