17	/// In-order Kanata pipeline viewer — writes Konata-compatible pipeline logs.
18	template<typename CPU>
19	class KanataViewer : public PipelineViewer<CPU>
20	{
21	public:
22	  KanataViewer(CPU& cpu,
23	               std::unique_ptr<kanata::KanataLogger> logger,
24	               kanata::PipelineConfig config)
25	      : logger_(std::move(logger))
26	  {
27	    auto vpu_config = config.vpu;
28	    modeler_ = std::make_unique<kanata::PipelineModeler<CPU>>(
29	      cpu, *logger_, std::move(config));
30	
31	    if (vpu_config) {
32	      vpu_modeler_ = std::make_unique<kanata::VpuPipelineModeler<CPU>>(
33	        cpu, *logger_, *modeler_, *vpu_config);
34	      modeler_->set_vpu(vpu_modeler_.get());
35	    }
36	  }
37	
38	  void on_cycle() override
39	  {
40	    modeler_->record();
41	    logger_->advance_cycle(1);
42	  }
43	
44	  void close() override { logger_->flush_all(); }
45	
46	  bool wants_exit() const override { return logger_->window_complete(); }
47	
48	private:
49	  std::unique_ptr<kanata::KanataLogger> logger_;
50	  std::unique_ptr<kanata::PipelineModeler<CPU>> modeler_;
51	  std::unique_ptr<kanata::VpuPipelineModeler<CPU>> vpu_modeler_;
52	};
