54	/// OoO Kanata pipeline viewer — age-based tracking for AX66 (single core).
55	template<typename CPU>
56	class OoOKanataViewer : public PipelineViewer<CPU>
57	{
58	public:
59	  OoOKanataViewer(CPU& cpu,
60	                  std::unique_ptr<kanata::KanataLogger> logger,
61	                  OoOPipelineConfig config)
62	      : logger_(std::move(logger))
63	      , modeler_(cpu, *logger_, std::move(config))
64	  {}
65	
66	  void on_cycle() override
67	  {
68	    modeler_.record();
69	    logger_->advance_cycle(1);
70	  }
71	
72	  void close() override
73	  {
74	    modeler_.finalize();
75	    logger_->flush_all();
76	  }
77	
78	  bool wants_exit() const override { return logger_->window_complete(); }
79	
80	private:
81	  std::unique_ptr<kanata::KanataLogger> logger_;
82	  OoOPipelineModeler<CPU> modeler_;
83	};
