85	/// Multi-core OoO Kanata viewer — wraps N independent OoOKanataViewers.
86	template<typename CPU>
87	class MultiCoreOoOKanataViewer : public PipelineViewer<CPU>
88	{
89	public:
90	  void add(std::unique_ptr<OoOKanataViewer<CPU>> viewer)
91	  {
92	    viewers_.push_back(std::move(viewer));
93	  }
94	
95	  void on_cycle() override
96	  {
97	    for (auto& v : viewers_)
98	      v->on_cycle();
99	  }
100	
101	  void close() override
102	  {
103	    for (auto& v : viewers_)
104	      v->close();
105	  }
106	
107	  bool wants_exit() const override
108	  {
109	    for (auto const& v : viewers_)
110	      if (v->wants_exit())
111	        return true;
112	    return false;
113	  }
114	
115	private:
116	  std::vector<std::unique_ptr<OoOKanataViewer<CPU>>> viewers_;
117	};
