119	/// Factory: create a pipeline viewer (in-order or OoO) if the CPU is
120	/// supported. Returns nullptr if no pipeline config matches the CPU.
121	///
122	/// For multi-core OoO (AX66 with NDS_NHART > 1), splits the output into
123	/// per-core files: "output.kanata" -> "output_core0.kanata",
124	/// "output_core1.kanata".
125	template<typename CPU>
126	std::unique_ptr<PipelineViewer<CPU>> make_kanata_viewer(
127	  CPU& cpu, const std::string& filename,
128	  const std::string& objdump_file = "",
129	  std::optional<kanata::LoopGate> gate = std::nullopt)
130	{
131	  // Try OoO path first (AX66)
132	  if (kanata::is_ooo_cpu(cpu.modelName())) {
133	    int num_cores = kanata::ax66_ooo_num_cores(cpu);
134	    spdlog::info("Kanata: detected AX66 OoO pipeline ({} core{})",
135	                 num_cores, num_cores > 1 ? "s" : "");
136	
137	    if (num_cores == 1) {
138	      // Single-core: one file, unchanged behavior
139	      auto logger = std::make_unique<kanata::KanataLogger>(filename, gate);
140	      if (!logger->is_open())
141	        return nullptr;
142	      if (!objdump_file.empty())
143	        logger->load_objdump(objdump_file);
144	      auto config = kanata::make_ax66_ooo_config(cpu, 0);
145	      return std::make_unique<OoOKanataViewer<CPU>>(
146	        cpu, std::move(logger), std::move(config));
147	    }
148	
149	    // Multi-core: split into per-core files
150	    namespace fs = std::filesystem;
151	    auto path = fs::path(filename);
152	    auto stem = path.stem().string();
153	    auto ext = path.extension().string();
154	    auto parent = path.parent_path();
155	
156	    auto multi = std::make_unique<MultiCoreOoOKanataViewer<CPU>>();
157	    for (int core = 0; core < num_cores; ++core) {
158	      auto core_file =
159	        (parent / fmt::format("{}_core{}{}", stem, core, ext)).string();
160	      spdlog::info("Kanata: core {} -> {}", core, core_file);
161	      auto logger = std::make_unique<kanata::KanataLogger>(core_file, gate);
162	      if (!logger->is_open())
163	        return nullptr;
164	      if (!objdump_file.empty())
165	        logger->load_objdump(objdump_file);
166	      auto config = kanata::make_ax66_ooo_config(cpu, core);
167	      multi->add(std::make_unique<OoOKanataViewer<CPU>>(
168	        cpu, std::move(logger), std::move(config)));
169	    }
170	    return multi;
171	  }
172	
173	  // In-order path
174	  auto config = kanata::detect_config(cpu.modelName());
175	  if (!config)
176	    return nullptr;
177	
178	  auto logger = std::make_unique<kanata::KanataLogger>(filename, gate);
179	  if (!logger->is_open())
180	    return nullptr;
181	
182	  if (!objdump_file.empty())
183	    logger->load_objdump(objdump_file);
184	
185	  return std::make_unique<KanataViewer<CPU>>(cpu, std::move(logger),
186	                                             std::move(*config));
187	}
